+  }
+  const who = mdSafe(labels.join(", "));
+  return f.consensus > 1 ? ` _(×${f.consensus}: ${who})_` : ` _[${who}]_`;
+}
+
+/** The honesty footer: which lenses ran, on which model, and that a clean/short result reflects only those. */
